#!/usr/bin/env bash
# AOT-tier coverage report over gnode/benchmarks — see
# examples/coverage_report.rs for what is measured (tiers A, A/C, B,
# and C = gg-walker interpreter-embed via aot_gg_embed's public API).
set -euo pipefail
cd "$(dirname "$0")/.."
exec cargo run --quiet --example coverage_report "$@"
